import React, {type PropsWithChildren} from "react";
import {ResponsiveElement, useSeparator} from "../../factory";
import type {IFlexComponent} from "@lmb-it/kitsconcerto-types";

const Center = ({className, children, ref, ...props}:PropsWithChildren<IFlexComponent>) => {
    // const {cssProps, nativeProps}  = split(props)
    const {cssProps, nativeProps}  = useSeparator<HTMLDivElement>(props)
    const { entering, exiting, ...restNativeProps } = nativeProps;

    return (
        <ResponsiveElement ref={ref} as="Center" entering={entering} exiting={exiting} additionalStyles={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
        }} additionalClasses={className} cssProps={cssProps} nativeProps={restNativeProps} children={children} />
    )
}
export default Center;
